import boto3

def publish_to_sqs(user_data):
    sqs = boto3.client('sqs')

    queue_url = 'Your_SQS_Queue_URL'

    response = sqs.send_message(
        QueueUrl=queue_url,
        DelaySeconds=10,
        MessageAttributes={
            'email': {
                'DataType': 'String',
                'StringValue': user_data['email']
            },
            'phone_number': {
                'DataType': 'String',
                'StringValue': user_data['phone_number']
            },
            'address': {
                'DataType': 'String',
                'StringValue': user_data['address']
            }
        },
        MessageBody=(
            'User PII data'
        )
    )

    return response

user_data = {
    'email': 'user@example.com',
    'phone_number': '1234567890',
    'address': '123 Main St, Anytown, USA'
}

publish_to_sqs(user_data)